import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { Button, Input, Slideout, TableCard } from '../../ui';
import {
  jobsService,
  type DataSyncSetConfigItem,
  type ExternalConnectorOptions,
  type ExternalConnectorTestConnectResult,
  type ExternalConnectorTestSearchResult,
  type TestExternalConnectorRequest,
  type UpdateDataSyncSetConfigRequest,
} from '../../services/jobs';
import { useAppToast } from '@linm-soft/common-components';
import styles from './DataSyncSetConfigPage.module.css';

const SLIDEOUT_WIDTH = '720px';

const defaultOptions = (): ExternalConnectorOptions => ({
  searchPath: '',
  detailPathTemplate: null,
  documentKeyField: 'soHoaDon',
  detailKeyParam: 'billId',
  pageSize: 100,
  parallelJobs: 4,
  timeoutSeconds: 60,
  maxRetries: 3,
  dateOffsetDays: 0,
  syncLookbackDays: 1,
  defaultFromDate: null,
  defaultToDate: null,
  apiKeyHeader: 'x-api-key',
  apiKey: null,
  apiKeyConfigKey: null,
  fetchDetailBeforeImport: true,
});

const parseOptions = (json?: string | null): ExternalConnectorOptions => {
  if (!json) return defaultOptions();
  try {
    return { ...defaultOptions(), ...JSON.parse(json) };
  } catch {
    return defaultOptions();
  }
};

const computeRangeFromOffset = (opt: ExternalConnectorOptions): { from: string; to: string } => {
  const to = new Date();
  to.setUTCDate(to.getUTCDate() - (opt.dateOffsetDays ?? 0));
  const from = new Date(to);
  from.setUTCDate(from.getUTCDate() - Math.max(0, (opt.syncLookbackDays ?? 1) - 1));
  const fmt = (d: Date) => d.toISOString().slice(0, 10);
  return { from: fmt(from), to: fmt(to) };
};

const resolveInitialSyncRange = (opt: ExternalConnectorOptions): { from: string; to: string } | null => {
  if (opt.defaultFromDate && opt.defaultToDate) {
    return { from: opt.defaultFromDate, to: opt.defaultToDate };
  }
  if (opt.dateOffsetDays !== undefined || opt.syncLookbackDays !== undefined) {
    return computeRangeFromOffset(opt);
  }
  return null;
};

const buildOptionsForSave = (
  options: ExternalConnectorOptions,
  apiKeyInput: string,
  existingJson?: string | null,
): ExternalConnectorOptions => {
  const existing = parseOptions(existingJson);
  const apiKey = apiKeyInput.trim() || existing.apiKey || null;
  return {
    ...options,
    apiKey,
    apiKeyConfigKey: null,
  };
};

type TestResponseState =
  | { kind: 'connect'; result: ExternalConnectorTestConnectResult }
  | { kind: 'search'; result: ExternalConnectorTestSearchResult };

const DataSyncSetConfigPage: React.FC = () => {
  useNavTitle('Cấu hình sync REVA FM');
  const toast = useAppToast();
  const navigate = useNavigate();
  const [rows, setRows] = React.useState<DataSyncSetConfigItem[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [editing, setEditing] = React.useState<DataSyncSetConfigItem | null>(null);
  const [form, setForm] = React.useState<UpdateDataSyncSetConfigRequest>({ isEnabled: true });
  const [options, setOptions] = React.useState<ExternalConnectorOptions>(defaultOptions());
  const [apiKeyInput, setApiKeyInput] = React.useState('');
  const [testFromDate, setTestFromDate] = React.useState('');
  const [testToDate, setTestToDate] = React.useState('');
  const [testResponse, setTestResponse] = React.useState<TestResponseState | null>(null);
  const [syncTarget, setSyncTarget] = React.useState<DataSyncSetConfigItem | null>(null);
  const [syncFromDate, setSyncFromDate] = React.useState('');
  const [syncToDate, setSyncToDate] = React.useState('');
  const [saving, setSaving] = React.useState(false);
  const [running, setRunning] = React.useState(false);
  const [testingConnect, setTestingConnect] = React.useState(false);
  const [testingSearch, setTestingSearch] = React.useState(false);

  const load = React.useCallback(() => {
    setLoading(true);
    jobsService
      .getExternalSetConfigs()
      .then(setRows)
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setLoading(false));
  }, [toast]);

  React.useEffect(() => load(), [load]);

  const closeEdit = () => {
    setEditing(null);
    setTestResponse(null);
  };

  const startEdit = (row: DataSyncSetConfigItem) => {
    setSyncTarget(null);
    setTestResponse(null);
    setEditing(row);
    setApiKeyInput('');
    setForm({
      isEnabled: row.isEnabled,
      externalBaseUrl: row.externalBaseUrl ?? '',
      endpointRouteTemplate: row.endpointRouteTemplate ?? '',
      chunkSize: row.chunkSize,
    });
    const opt = parseOptions(row.optionsJson);
    setOptions(opt);
    const range = resolveInitialSyncRange(opt);
    setTestFromDate(range?.from ?? '');
    setTestToDate(range?.to ?? '');
  };

  const openSyncRequest = (row: DataSyncSetConfigItem) => {
    const opt = parseOptions(row.optionsJson);
    if (!row.externalBaseUrl?.trim() || !opt.searchPath?.trim()) {
      toast.error('Cấu hình Base URL và Search path trong Sửa trước khi tạo sync.');
      return;
    }
    if (!opt.apiKey && !opt.apiKeyConfigKey) {
      toast.error('Cấu hình API key trong Sửa trước khi tạo sync.');
      return;
    }

    setEditing(null);
    setSyncTarget(row);
    const range = resolveInitialSyncRange(opt);
    if (!range) {
      toast.error('Cấu hình Từ ngày / Đến ngày mặc định (hoặc offset + lookback) trong Sửa.');
      setSyncFromDate('');
      setSyncToDate('');
      return;
    }
    setSyncFromDate(range.from);
    setSyncToDate(range.to);
  };

  const validateConnectorDraft = (): boolean => {
    if (!form.externalBaseUrl?.trim()) {
      toast.error('Base URL là bắt buộc');
      return false;
    }
    if (!options.searchPath?.trim()) {
      toast.error('Search path là bắt buộc');
      return false;
    }
    const merged = buildOptionsForSave(options, apiKeyInput, editing?.optionsJson);
    const hadKey = Boolean(parseOptions(editing?.optionsJson).apiKey);
    if (!merged.apiKey && !hadKey && !apiKeyInput.trim()) {
      toast.error('API key là bắt buộc (lưu trên UI, không dùng appsettings)');
      return false;
    }
    if (!testFromDate || !testToDate) {
      toast.error('Chọn Từ ngày và Đến ngày để test');
      return false;
    }
    if (testFromDate > testToDate) {
      toast.error('Từ ngày không được lớn hơn Đến ngày');
      return false;
    }
    return true;
  };

  const buildTestRequest = (): TestExternalConnectorRequest => {
    const merged = buildOptionsForSave(options, apiKeyInput, editing?.optionsJson);
    return {
      externalBaseUrl: form.externalBaseUrl,
      optionsJson: JSON.stringify(merged),
      fromDate: testFromDate,
      toDate: testToDate,
      pageSize: 5,
    };
  };

  const runTestConnect = async () => {
    if (!editing || !validateConnectorDraft()) return;
    setTestingConnect(true);
    setTestResponse(null);
    try {
      const result = await jobsService.testExternalConnectorConnect(editing.configKey, buildTestRequest());
      setTestResponse({ kind: 'connect', result });
      if (result.success) {
        toast.success(`Kết nối OK — totalItems: ${result.totalItems}`);
      } else {
        toast.error(result.message || 'Test kết nối thất bại');
      }
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi test kết nối');
    } finally {
      setTestingConnect(false);
    }
  };

  const runTestSearch = async () => {
    if (!editing || !validateConnectorDraft()) return;
    setTestingSearch(true);
    setTestResponse(null);
    try {
      const result = await jobsService.testExternalConnectorSearch(editing.configKey, buildTestRequest());
      setTestResponse({ kind: 'search', result });
      if (result.success) {
        toast.success(`Search OK — ${result.itemCount} item / total ${result.totalItems}`);
      } else {
        toast.error(result.message || 'Test search thất bại');
      }
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi test search');
    } finally {
      setTestingSearch(false);
    }
  };

  const save = async () => {
    if (!editing) return;

    if (!validateConnectorDraft()) return;

    const merged = buildOptionsForSave(options, apiKeyInput, editing.optionsJson);

    setSaving(true);
    try {
      await jobsService.updateExternalSetConfig(editing.configKey, {
        ...form,
        optionsJson: JSON.stringify(merged, null, 2),
      });
      toast.success('Đã lưu cấu hình');
      closeEdit();
      load();
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi lưu');
    } finally {
      setSaving(false);
    }
  };

  const submitSyncRequest = async () => {
    if (!syncTarget) return;
    if (!syncFromDate || !syncToDate) {
      toast.error('Chọn Từ ngày và Đến ngày');
      return;
    }
    if (syncFromDate > syncToDate) {
      toast.error('Từ ngày không được lớn hơn Đến ngày');
      return;
    }

    setRunning(true);
    try {
      const res = await jobsService.triggerExternalSync(syncTarget.configKey, {
        fromDate: syncFromDate,
        toDate: syncToDate,
      });
      toast.success(`Đã tạo yêu cầu sync — runId ${res.runId.slice(0, 8)}…`);
      setSyncTarget(null);
      navigate(`/admin/jobs/external-runs?runId=${res.runId}`);
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi tạo yêu cầu sync');
    } finally {
      setRunning(false);
    }
  };

  const renderTestResponse = () => {
    if (!testResponse) return null;

    if (testResponse.kind === 'connect') {
      const r = testResponse.result;
      return (
        <div
          className={`${styles.responseBlock} ${r.success ? styles.responseOk : styles.responseErr}`}
          data-testid="connector-test-connect-response"
        >
          {JSON.stringify(
            {
              success: r.success,
              httpStatus: r.httpStatus,
              message: r.message,
              totalItems: r.totalItems,
              elapsedMs: r.elapsedMs,
              requestUrl: r.requestUrl,
            },
            null,
            2,
          )}
        </div>
      );
    }

    const r = testResponse.result;
    return (
      <div
        className={`${styles.responseBlock} ${r.success ? styles.responseOk : styles.responseErr}`}
        data-testid="connector-test-search-response"
      >
        {r.responseJson || JSON.stringify({ message: r.message, httpStatus: r.httpStatus }, null, 2)}
      </div>
    );
  };

  return (
    <div data-testid="data-sync-set-config-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
        {' · '}
        <Link to="/admin/jobs/external-runs">Theo dõi sync ngoài</Link>
        {' · '}
        <Link to="/admin/jobs/inbound">Inbound dashboard</Link>
      </p>
      <p style={{ color: '#555', marginBottom: 16 }}>
        Mọi tham số connector (URL, API key, pageSize, parallel, timeout, retry, ngày mặc định) được{' '}
        <strong>cấu hình và lưu trên UI</strong> — bảng <code>data_sync_set_configs</code>.
      </p>

      {syncTarget ? (
        <div style={{ marginBottom: 16 }}>
          <TableCard>
            <div style={{ padding: 16 }}>
              <h3 style={{ marginTop: 0 }}>Tạo yêu cầu sync — {syncTarget.configKey}</h3>
              <p style={{ color: '#666', fontSize: 14, marginBottom: 12 }}>
                Khoảng ngày gửi vào <code>criterias.fromDate</code> / <code>toDate</code> khi search REVA FM.
              </p>
              <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'flex-end' }}>
                <Input
                  label="Từ ngày"
                  type="date"
                  value={syncFromDate}
                  onChange={(e) => setSyncFromDate(e.target.value)}
                  data-testid="sync-from-date"
                />
                <Input
                  label="Đến ngày"
                  type="date"
                  value={syncToDate}
                  onChange={(e) => setSyncToDate(e.target.value)}
                  data-testid="sync-to-date"
                />
                <Button type="button" onClick={submitSyncRequest} disabled={running}>
                  {running ? 'Đang gửi…' : 'Tạo yêu cầu sync'}
                </Button>
                <Button type="button" variant="secondary" onClick={() => setSyncTarget(null)}>
                  Hủy
                </Button>
              </div>
            </div>
          </TableCard>
        </div>
      ) : null}

      <TableCard>
        {loading ? (
          <p>Đang tải…</p>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr>
                <th align="left">Connector</th>
                <th align="left">Base URL</th>
                <th align="left">Ngày mặc định</th>
                <th align="left">Bật</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {rows.map((r) => {
                const opt = parseOptions(r.optionsJson);
                const defaultRange =
                  opt.defaultFromDate && opt.defaultToDate
                    ? `${opt.defaultFromDate} → ${opt.defaultToDate}`
                    : `Offset ${opt.dateOffsetDays}d / lookback ${opt.syncLookbackDays}d`;
                return (
                  <tr key={r.configKey}>
                    <td>
                      <strong>{r.configKey}</strong>
                      <br />
                      <small>{opt.searchPath || '—'}</small>
                    </td>
                    <td style={{ fontSize: 12 }}>{r.externalBaseUrl ?? '—'}</td>
                    <td style={{ fontSize: 12 }}>{defaultRange}</td>
                    <td>{r.isEnabled ? 'Có' : 'Không'}</td>
                    <td style={{ whiteSpace: 'nowrap' }}>
                      <Button type="button" variant="secondary" onClick={() => startEdit(r)} style={{ marginRight: 8 }}>
                        Sửa
                      </Button>
                      <Button type="button" onClick={() => openSyncRequest(r)} disabled={!r.isEnabled}>
                        Tạo sync
                      </Button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </TableCard>

      <Slideout
        isOpen={Boolean(editing)}
        onClose={closeEdit}
        title={editing ? `Cấu hình connector — ${editing.configKey}` : ''}
        width={SLIDEOUT_WIDTH}
        customFooter={
          <div className={styles.footerBtns}>
            <button type="button" className={styles.cancelBtn} onClick={closeEdit} disabled={saving}>
              Hủy
            </button>
            <button type="button" className={styles.saveBtn} onClick={save} disabled={saving}>
              {saving ? 'Đang lưu…' : 'Lưu cấu hình'}
            </button>
          </div>
        }
      >
        {editing ? (
          <div className={styles.slideoutBody} data-testid="connector-config-slideout">
            <section className={styles.section}>
              <h4 className={styles.sectionTitle}>Kết nối REVA FM</h4>
              <label className={styles.checkboxRow}>
                <input
                  type="checkbox"
                  checked={form.isEnabled}
                  onChange={(e) => setForm((f) => ({ ...f, isEnabled: e.target.checked }))}
                />
                Bật connector
              </label>
              <Input
                label="Base URL"
                value={form.externalBaseUrl ?? ''}
                onChange={(e) => setForm((f) => ({ ...f, externalBaseUrl: e.target.value }))}
                placeholder="https://foodmart-share-api.bosssoft.vn"
              />
              <Input
                label="Header API key"
                value={options.apiKeyHeader}
                onChange={(e) => setOptions((o) => ({ ...o, apiKeyHeader: e.target.value || 'x-api-key' }))}
              />
              <Input
                label="API key"
                type="password"
                value={apiKeyInput}
                onChange={(e) => setApiKeyInput(e.target.value)}
                placeholder={
                  parseOptions(editing.optionsJson).apiKey
                    ? 'Để trống = giữ key đã lưu'
                    : 'Bắt buộc — lưu trên UI'
                }
              />
              <Input
                label="Search path (POST)"
                value={options.searchPath}
                onChange={(e) => setOptions((o) => ({ ...o, searchPath: e.target.value }))}
                placeholder="/api/RevaPlashform/TimHoaDon"
              />
              <Input
                label="Detail path (GET, {id})"
                value={options.detailPathTemplate ?? ''}
                onChange={(e) => setOptions((o) => ({ ...o, detailPathTemplate: e.target.value || null }))}
                placeholder="/api/RevaPlashform/ChiTietHoaDon?billId={id}"
              />
              <div className={styles.grid2}>
                <Input
                  label="Trường khóa document"
                  value={options.documentKeyField}
                  onChange={(e) => setOptions((o) => ({ ...o, documentKeyField: e.target.value }))}
                />
                <Input
                  label="Query param detail"
                  value={options.detailKeyParam}
                  onChange={(e) => setOptions((o) => ({ ...o, detailKeyParam: e.target.value }))}
                />
              </div>
              <label className={styles.checkboxRow}>
                <input
                  type="checkbox"
                  checked={options.fetchDetailBeforeImport}
                  onChange={(e) => setOptions((o) => ({ ...o, fetchDetailBeforeImport: e.target.checked }))}
                />
                Gọi API detail trước khi import
              </label>
            </section>

            <section className={styles.section}>
              <h4 className={styles.sectionTitle}>Job sync (search / parallel / retry)</h4>
              <div className={styles.grid2}>
                <Input
                  label="Page size (sau probe)"
                  type="number"
                  value={String(options.pageSize)}
                  onChange={(e) => setOptions((o) => ({ ...o, pageSize: Number(e.target.value) || 1 }))}
                />
                <Input
                  label="Số job song song"
                  type="number"
                  value={String(options.parallelJobs)}
                  onChange={(e) => setOptions((o) => ({ ...o, parallelJobs: Number(e.target.value) || 1 }))}
                />
                <Input
                  label="Timeout (giây)"
                  type="number"
                  value={String(options.timeoutSeconds)}
                  onChange={(e) => setOptions((o) => ({ ...o, timeoutSeconds: Number(e.target.value) || 60 }))}
                />
                <Input
                  label="Số lần retry"
                  type="number"
                  value={String(options.maxRetries)}
                  onChange={(e) => setOptions((o) => ({ ...o, maxRetries: Number(e.target.value) || 3 }))}
                />
              </div>
            </section>

            <section className={styles.section}>
              <h4 className={styles.sectionTitle}>Khoảng ngày (tạo yêu cầu sync / test)</h4>
              <div className={styles.grid2}>
                <Input
                  label="Từ ngày mặc định"
                  type="date"
                  value={options.defaultFromDate ?? ''}
                  onChange={(e) =>
                    setOptions((o) => ({ ...o, defaultFromDate: e.target.value || null }))
                  }
                />
                <Input
                  label="Đến ngày mặc định"
                  type="date"
                  value={options.defaultToDate ?? ''}
                  onChange={(e) =>
                    setOptions((o) => ({ ...o, defaultToDate: e.target.value || null }))
                  }
                />
                <Input
                  label="Offset ngày (nếu chưa set mặc định)"
                  type="number"
                  value={String(options.dateOffsetDays)}
                  onChange={(e) => setOptions((o) => ({ ...o, dateOffsetDays: Number(e.target.value) || 0 }))}
                />
                <Input
                  label="Lookback (ngày)"
                  type="number"
                  value={String(options.syncLookbackDays)}
                  onChange={(e) => setOptions((o) => ({ ...o, syncLookbackDays: Number(e.target.value) || 1 }))}
                />
              </div>
            </section>

            <section className={styles.section}>
              <h4 className={styles.sectionTitle}>Import ERP (tùy chọn)</h4>
              <Input
                label="Route import ERP"
                value={form.endpointRouteTemplate ?? ''}
                onChange={(e) => setForm((f) => ({ ...f, endpointRouteTemplate: e.target.value }))}
                placeholder="api/v1/… (để trống nếu chưa có endpoint)"
              />
            </section>

            <section className={`${styles.section} ${styles.testPanel}`}>
              <h4 className={styles.sectionTitle}>Test connector (draft — chưa cần Lưu)</h4>
              <p style={{ margin: 0, fontSize: 13, color: '#666' }}>
                Gửi POST search với <code>criterias.fromDate</code> / <code>toDate</code> tới REVA FM và hiển thị response.
              </p>
              <div className={styles.grid2}>
                <Input
                  label="Từ ngày test"
                  type="date"
                  value={testFromDate}
                  onChange={(e) => setTestFromDate(e.target.value)}
                  data-testid="connector-test-from-date"
                />
                <Input
                  label="Đến ngày test"
                  type="date"
                  value={testToDate}
                  onChange={(e) => setTestToDate(e.target.value)}
                  data-testid="connector-test-to-date"
                />
              </div>
              <div className={styles.testActions}>
                <Button
                  type="button"
                  variant="secondary"
                  onClick={runTestConnect}
                  disabled={testingConnect || testingSearch}
                  data-testid="connector-test-connect-btn"
                >
                  {testingConnect ? 'Đang test…' : 'Test kết nối'}
                </Button>
                <Button
                  type="button"
                  variant="secondary"
                  onClick={runTestSearch}
                  disabled={testingConnect || testingSearch}
                  data-testid="connector-test-search-btn"
                >
                  {testingSearch ? 'Đang search…' : 'Test search data'}
                </Button>
              </div>
              {testResponse ? (
                <p className={styles.testMeta}>
                  <strong>
                    {testResponse.kind === 'connect' ? 'Test kết nối' : 'Test search'}:
                  </strong>{' '}
                  {testResponse.result.success ? 'Thành công' : 'Thất bại'}
                  {testResponse.result.httpStatus ? ` · HTTP ${testResponse.result.httpStatus}` : ''}
                  {' · '}
                  {testResponse.result.elapsedMs} ms
                  {testResponse.kind === 'search' && testResponse.result.success
                    ? ` · ${testResponse.result.itemCount}/${testResponse.result.totalItems} items`
                    : testResponse.kind === 'connect' && testResponse.result.success
                      ? ` · totalItems: ${testResponse.result.totalItems}`
                      : ''}
                </p>
              ) : null}
              {renderTestResponse()}
            </section>
          </div>
        ) : null}
      </Slideout>
    </div>
  );
};

export default DataSyncSetConfigPage;
