import React from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { Button, TableCard } from '../../ui';
import {
  jobsService,
  type DataSyncCheckpointItem,
  type DataSyncRunDetail,
  type DataSyncRunListItem,
} from '../../services/jobs';
import { useAppToast } from '@linm-soft/common-components';

const RUNNING_STATUSES = new Set(['Running']);

const statusColor = (status: string): string => {
  switch (status) {
    case 'Done':
    case 'Success':
      return '#15803d';
    case 'Failed':
      return '#b91c1c';
    case 'Processing':
    case 'Running':
      return '#2563eb';
    case 'Partial':
      return '#ca8a04';
    default:
      return '#64748b';
  }
};

const formatDate = (iso: string) => new Date(iso).toLocaleString('vi-VN');

const ExternalSyncRunsPage: React.FC = () => {
  useNavTitle('Theo dõi sync ngoài (REVA FM)');
  const toast = useAppToast();
  const [searchParams, setSearchParams] = useSearchParams();

  const [runs, setRuns] = React.useState<DataSyncRunListItem[]>([]);
  const [runsTotal, setRunsTotal] = React.useState(0);
  const [runsPage, setRunsPage] = React.useState(1);
  const [selectedRunId, setSelectedRunId] = React.useState<string | null>(searchParams.get('runId'));
  const [runDetail, setRunDetail] = React.useState<DataSyncRunDetail | null>(null);
  const [checkpoints, setCheckpoints] = React.useState<DataSyncCheckpointItem[]>([]);
  const [checkpointsTotal, setCheckpointsTotal] = React.useState(0);
  const [checkpointPage, setCheckpointPage] = React.useState(1);
  const [checkpointStatus, setCheckpointStatus] = React.useState('');
  const [loadingRuns, setLoadingRuns] = React.useState(true);
  const [loadingDetail, setLoadingDetail] = React.useState(false);

  const loadRuns = React.useCallback(() => {
    setLoadingRuns(true);
    jobsService
      .getDataSyncRuns(runsPage, 20, 'External')
      .then((r) => {
        setRuns(r.items);
        setRunsTotal(r.total);
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setLoadingRuns(false));
  }, [runsPage, toast]);

  const loadDetail = React.useCallback(
    (runId: string) => {
      setLoadingDetail(true);
      return jobsService
        .getDataSyncRun(runId)
        .then(setRunDetail)
        .catch((e: Error) => {
          toast.error(e.message);
          setRunDetail(null);
        })
        .finally(() => setLoadingDetail(false));
    },
    [toast],
  );

  const loadCheckpoints = React.useCallback(
    (runId: string) => {
      jobsService
        .getRunCheckpoints(runId, checkpointPage, 50, checkpointStatus || undefined)
        .then((r) => {
          setCheckpoints(r.items);
          setCheckpointsTotal(r.total);
        })
        .catch((e: Error) => toast.error(e.message));
    },
    [checkpointPage, checkpointStatus, toast],
  );

  React.useEffect(() => {
    loadRuns();
  }, [loadRuns]);

  React.useEffect(() => {
    const fromUrl = searchParams.get('runId');
    if (fromUrl && fromUrl !== selectedRunId) {
      setSelectedRunId(fromUrl);
    }
  }, [searchParams, selectedRunId]);

  React.useEffect(() => {
    if (!selectedRunId) {
      setRunDetail(null);
      setCheckpoints([]);
      return;
    }
    setRunDetail(null);
    loadDetail(selectedRunId);
  }, [selectedRunId, loadDetail]);

  React.useEffect(() => {
    if (!selectedRunId) return;
    loadCheckpoints(selectedRunId);
  }, [selectedRunId, checkpointPage, checkpointStatus, loadCheckpoints]);

  React.useEffect(() => {
    if (!selectedRunId || !runDetail || !RUNNING_STATUSES.has(runDetail.status)) return undefined;
    const timer = setInterval(() => {
      loadDetail(selectedRunId);
      loadCheckpoints(selectedRunId);
      loadRuns();
    }, 4000);
    return () => clearInterval(timer);
  }, [selectedRunId, runDetail?.status, loadDetail, loadCheckpoints, loadRuns]);

  const selectRun = (runId: string) => {
    setSelectedRunId(runId);
    setCheckpointPage(1);
    setSearchParams({ runId });
  };

  const runsPages = Math.max(1, Math.ceil(runsTotal / 20));
  const checkpointPages = Math.max(1, Math.ceil(checkpointsTotal / 50));

  return (
    <div data-testid="external-sync-runs-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
        {' · '}
        <Link to="/admin/jobs/external-sync">Cấu hình sync REVA</Link>
      </p>

      <p style={{ color: '#555', marginBottom: 16 }}>
        Danh sách run pull từ hệ ngoài (bảng <code>data_sync_runs</code>, kind External) và tiến độ checkpoint
        từng chứng từ.
      </p>

      <div style={{ display: 'grid', gridTemplateColumns: 'minmax(280px, 360px) 1fr', gap: 16 }}>
        <TableCard>
          <div style={{ padding: 12 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
              <h4 style={{ margin: 0 }}>Danh sách run</h4>
              <Button type="button" variant="secondary" onClick={loadRuns} disabled={loadingRuns}>
                Làm mới
              </Button>
            </div>
            {loadingRuns && runs.length === 0 ? <p>Đang tải…</p> : null}
            <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
              {runs.map((r) => (
                <li key={r.id} style={{ marginBottom: 8 }}>
                  <button
                    type="button"
                    onClick={() => selectRun(r.id)}
                    style={{
                      width: '100%',
                      textAlign: 'left',
                      padding: 10,
                      border: selectedRunId === r.id ? '2px solid #2563eb' : '1px solid #e2e8f0',
                      borderRadius: 8,
                      background: selectedRunId === r.id ? '#eff6ff' : '#fff',
                      cursor: 'pointer',
                    }}
                  >
                    <div style={{ display: 'flex', justifyContent: 'space-between', gap: 8 }}>
                      <strong style={{ color: statusColor(r.status) }}>{r.status}</strong>
                      <span style={{ fontSize: 12, color: '#64748b' }}>{r.progressPercent}%</span>
                    </div>
                    <div style={{ fontSize: 13, marginTop: 4 }}>
                      {r.setsRequested.join(', ') || '—'}
                    </div>
                    <small style={{ color: '#64748b' }}>{formatDate(r.startedAtUtc)}</small>
                    <br />
                    <small style={{ fontFamily: 'monospace', fontSize: 11, color: '#94a3b8' }}>
                      {r.id.slice(0, 8)}…
                    </small>
                  </button>
                </li>
              ))}
            </ul>
            {runs.length === 0 && !loadingRuns ? <p style={{ color: '#64748b' }}>Chưa có run nào.</p> : null}
            {runsPages > 1 ? (
              <div style={{ display: 'flex', gap: 8, marginTop: 12, alignItems: 'center' }}>
                <Button
                  type="button"
                  variant="secondary"
                  disabled={runsPage <= 1}
                  onClick={() => setRunsPage((p) => Math.max(1, p - 1))}
                >
                  Trước
                </Button>
                <span style={{ fontSize: 13 }}>
                  {runsPage}/{runsPages}
                </span>
                <Button
                  type="button"
                  variant="secondary"
                  disabled={runsPage >= runsPages}
                  onClick={() => setRunsPage((p) => p + 1)}
                >
                  Sau
                </Button>
              </div>
            ) : null}
          </div>
        </TableCard>

        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          <TableCard>
            <div style={{ padding: 16 }}>
              <h4 style={{ marginTop: 0 }}>Chi tiết run</h4>
              {!selectedRunId ? (
                <p style={{ color: '#64748b' }}>Chọn một run bên trái để xem tiến độ.</p>
              ) : loadingDetail && !runDetail ? (
                <p>Đang tải…</p>
              ) : runDetail ? (
                <>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: 12, marginBottom: 16 }}>
                    <div>
                      <div style={{ fontSize: 12, color: '#64748b' }}>Trạng thái</div>
                      <strong style={{ color: statusColor(runDetail.status) }}>{runDetail.status}</strong>
                    </div>
                    <div>
                      <div style={{ fontSize: 12, color: '#64748b' }}>Trigger</div>
                      <strong>{runDetail.trigger}</strong>
                    </div>
                    <div>
                      <div style={{ fontSize: 12, color: '#64748b' }}>Connector</div>
                      <strong>{runDetail.setsRequested.join(', ') || '—'}</strong>
                    </div>
                    <div>
                      <div style={{ fontSize: 12, color: '#64748b' }}>Tiến độ</div>
                      <strong>{runDetail.progressPercent}%</strong>
                    </div>
                  </div>

                  {runDetail.progress ? (
                    <div style={{ marginBottom: 16 }}>
                      <div
                        style={{
                          height: 8,
                          background: '#e2e8f0',
                          borderRadius: 4,
                          overflow: 'hidden',
                          marginBottom: 8,
                        }}
                      >
                        <div
                          style={{
                            width: `${runDetail.progress.progressPercent}%`,
                            height: '100%',
                            background: '#2563eb',
                          }}
                        />
                      </div>
                      <ul style={{ margin: 0, paddingLeft: 18 }}>
                        {runDetail.progress.sets.map((s) => (
                          <li key={s.setName}>
                            {s.setName}: {s.documentsDone}/{s.documentsTotal} xong
                            {s.documentsFailed > 0 ? `, ${s.documentsFailed} lỗi` : ''}
                            {' '}({s.progressPercent}%)
                          </li>
                        ))}
                      </ul>
                    </div>
                  ) : (
                    <p style={{ color: '#64748b' }}>Chưa có checkpoint — run có thể đang khởi tạo.</p>
                  )}

                  <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap', fontSize: 13 }}>
                    <span>
                      Checkpoint: <strong>{runDetail.checkpointSummary.total}</strong>
                    </span>
                    <span style={{ color: statusColor('Done') }}>
                      Done: {runDetail.checkpointSummary.done}
                    </span>
                    <span style={{ color: statusColor('Processing') }}>
                      Processing: {runDetail.checkpointSummary.processing}
                    </span>
                    <span style={{ color: statusColor('Pending') }}>
                      Pending: {runDetail.checkpointSummary.pending}
                    </span>
                    <span style={{ color: statusColor('Failed') }}>
                      Failed: {runDetail.checkpointSummary.failed}
                    </span>
                  </div>

                  <p style={{ fontSize: 12, color: '#94a3b8', marginBottom: 0, marginTop: 12 }}>
                    Bắt đầu: {formatDate(runDetail.startedAtUtc)}
                    {runDetail.finishedAtUtc ? ` · Kết thúc: ${formatDate(runDetail.finishedAtUtc)}` : ''}
                  </p>
                </>
              ) : (
                <p style={{ color: '#64748b' }}>Không tải được chi tiết run.</p>
              )}
            </div>
          </TableCard>

          <TableCard>
            <div style={{ padding: 16 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 12, marginBottom: 12 }}>
                <h4 style={{ margin: 0 }}>Checkpoint theo chứng từ</h4>
                <label style={{ fontSize: 13, display: 'flex', alignItems: 'center', gap: 8 }}>
                  Lọc trạng thái
                  <select
                    value={checkpointStatus}
                    onChange={(e) => {
                      setCheckpointStatus(e.target.value);
                      setCheckpointPage(1);
                    }}
                    style={{ padding: '4px 8px', borderRadius: 4, border: '1px solid #cbd5e1' }}
                  >
                    <option value="">Tất cả</option>
                    <option value="Pending">Pending</option>
                    <option value="Processing">Processing</option>
                    <option value="Done">Done</option>
                    <option value="Failed">Failed</option>
                  </select>
                </label>
              </div>

              {!selectedRunId ? (
                <p style={{ color: '#64748b' }}>Chọn run để xem checkpoint.</p>
              ) : (
                <>
                  <div style={{ overflowX: 'auto' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
                      <thead>
                        <tr style={{ borderBottom: '1px solid #e2e8f0' }}>
                          <th align="left" style={{ padding: '8px 4px' }}>Set</th>
                          <th align="left" style={{ padding: '8px 4px' }}>Mã chứng từ</th>
                          <th align="left" style={{ padding: '8px 4px' }}>Trạng thái</th>
                          <th align="left" style={{ padding: '8px 4px' }}>Cập nhật</th>
                        </tr>
                      </thead>
                      <tbody>
                        {checkpoints.map((c) => (
                          <tr key={c.id} style={{ borderBottom: '1px solid #f1f5f9' }}>
                            <td style={{ padding: '8px 4px' }}>{c.setName}</td>
                            <td style={{ padding: '8px 4px', fontFamily: 'monospace' }}>{c.documentKey}</td>
                            <td style={{ padding: '8px 4px', color: statusColor(c.status), fontWeight: 600 }}>
                              {c.status}
                            </td>
                            <td style={{ padding: '8px 4px', color: '#64748b' }}>{formatDate(c.updatedAtUtc)}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                  {checkpoints.length === 0 ? (
                    <p style={{ color: '#64748b', marginTop: 12 }}>Không có checkpoint phù hợp bộ lọc.</p>
                  ) : null}
                  {checkpointPages > 1 ? (
                    <div style={{ display: 'flex', gap: 8, marginTop: 12, alignItems: 'center' }}>
                      <Button
                        type="button"
                        variant="secondary"
                        disabled={checkpointPage <= 1}
                        onClick={() => setCheckpointPage((p) => Math.max(1, p - 1))}
                      >
                        Trước
                      </Button>
                      <span style={{ fontSize: 13 }}>
                        {checkpointPage}/{checkpointPages} ({checkpointsTotal} dòng)
                      </span>
                      <Button
                        type="button"
                        variant="secondary"
                        disabled={checkpointPage >= checkpointPages}
                        onClick={() => setCheckpointPage((p) => p + 1)}
                      >
                        Sau
                      </Button>
                    </div>
                  ) : null}
                </>
              )}
            </div>
          </TableCard>
        </div>
      </div>
    </div>
  );
};

export default ExternalSyncRunsPage;
