import React from 'react';
import { Link } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { Button, Input, TableCard } from '../../ui';
import { jobsService, type PlatformJobScheduleConfig, type UpdateScheduleConfigRequest } from '../../services/jobs';
import { useAppToast } from '@linm-soft/common-components';

const JobScheduleConfigPage: React.FC = () => {
  useNavTitle('Cấu hình job / lịch chạy');
  const toast = useAppToast();
  const [rows, setRows] = React.useState<PlatformJobScheduleConfig[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [editing, setEditing] = React.useState<PlatformJobScheduleConfig | null>(null);
  const [form, setForm] = React.useState<UpdateScheduleConfigRequest>({
    enabled: true,
    autoRunOnStartup: false,
    scheduleCron: '',
    scheduleIntervalMinutes: undefined,
  });
  const [saving, setSaving] = React.useState(false);

  const load = React.useCallback(() => {
    setLoading(true);
    jobsService
      .getScheduleConfigs()
      .then(setRows)
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setLoading(false));
  }, [toast]);

  React.useEffect(() => load(), [load]);

  const startEdit = (row: PlatformJobScheduleConfig) => {
    setEditing(row);
    setForm({
      enabled: row.enabled,
      autoRunOnStartup: row.autoRunOnStartup,
      scheduleCron: row.scheduleCron ?? '',
      scheduleIntervalMinutes: row.scheduleIntervalMinutes ?? undefined,
    });
  };

  const save = async () => {
    if (!editing) return;
    setSaving(true);
    try {
      await jobsService.updateScheduleConfig(editing.jobKey, {
        ...form,
        scheduleCron: form.scheduleCron || null,
        scheduleIntervalMinutes: form.scheduleIntervalMinutes || null,
      });
      toast.success('Đã lưu cấu hình job');
      setEditing(null);
      load();
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi lưu');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div data-testid="job-schedule-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
      </p>
      <p style={{ color: '#555', marginBottom: 16 }}>
        Cấu hình bật/tắt, chạy khi startup và lịch (cron hoặc interval phút). Worker thực thi vẫn do
        LinmPlatformEventing — bảng này là metadata admin (áp dụng dần theo từng job).
      </p>

      <TableCard>
        {loading ? (
          <p>Đang tải…</p>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr>
                <th align="left">Job</th>
                <th align="left">Hướng</th>
                <th align="left">Startup</th>
                <th align="left">Cron</th>
                <th align="left">Interval (phút)</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {rows.map((r) => (
                <tr key={r.jobKey}>
                  <td>{r.displayName}</td>
                  <td>{r.direction}</td>
                  <td>{r.autoRunOnStartup ? 'Có' : 'Không'}</td>
                  <td>{r.scheduleCron ?? '—'}</td>
                  <td>{r.scheduleIntervalMinutes ?? '—'}</td>
                  <td>
                    <Button type="button" variant="secondary" onClick={() => startEdit(r)}>
                      Sửa
                    </Button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </TableCard>

      {editing ? (
        <div style={{ marginTop: 24, maxWidth: 480 }}>
          <h3>Sửa: {editing.displayName}</h3>
          <label style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 8 }}>
            <input
              type="checkbox"
              checked={form.enabled}
              onChange={(e) => setForm((f) => ({ ...f, enabled: e.target.checked }))}
            />
            Enabled
          </label>
          <label style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 8 }}>
            <input
              type="checkbox"
              checked={form.autoRunOnStartup}
              onChange={(e) => setForm((f) => ({ ...f, autoRunOnStartup: e.target.checked }))}
            />
            Auto run on startup
          </label>
          <Input
            label="Cron (tùy chọn)"
            value={form.scheduleCron ?? ''}
            onChange={(e) => setForm((f) => ({ ...f, scheduleCron: e.target.value }))}
          />
          <Input
            label="Interval phút (tùy chọn)"
            type="number"
            value={form.scheduleIntervalMinutes?.toString() ?? ''}
            onChange={(e) =>
              setForm((f) => ({
                ...f,
                scheduleIntervalMinutes: e.target.value ? Number(e.target.value) : undefined,
              }))
            }
          />
          <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
            <Button type="button" onClick={save} disabled={saving}>
              Lưu
            </Button>
            <Button type="button" variant="secondary" onClick={() => setEditing(null)}>
              Hủy
            </Button>
          </div>
        </div>
      ) : null}
    </div>
  );
};

export default JobScheduleConfigPage;
