import React from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { CatalogListPageTabs, TableCard, Tabs } from '../../ui';
import {
  JOB_INTERNAL_TABS,
  resolveJobInternalTab,
  type JobInternalTabId,
} from '../../config/adminPages';
import { jobsService } from '../../services/jobs';
import { JobEventTypeFilter } from './components/JobEventTypeFilter';
import { useAppToast } from '@linm-soft/common-components';

const JobInternalPage: React.FC = () => {
  useNavTitle('Job nội bộ — import & event');
  const toast = useAppToast();
  const [searchParams, setSearchParams] = useSearchParams();
  const [tab, setTab] = React.useState<JobInternalTabId>(() =>
    resolveJobInternalTab(searchParams.get('tab')),
  );
  const [eventTypes, setEventTypes] = React.useState<Awaited<ReturnType<typeof jobsService.getEventTypes>>>([]);
  const [eventType, setEventType] = React.useState('');
  const [status, setStatus] = React.useState('');
  const [events, setEvents] = React.useState<Awaited<ReturnType<typeof jobsService.getEvents>>['items']>([]);
  const [runs, setRuns] = React.useState<Awaited<ReturnType<typeof jobsService.getImportRuns>>['items']>([]);
  const [selectedRunId, setSelectedRunId] = React.useState<string | null>(null);
  const [runDetail, setRunDetail] = React.useState<Awaited<ReturnType<typeof jobsService.getImportRun>> | null>(null);
  const [loading, setLoading] = React.useState(false);

  React.useEffect(() => {
    const next = resolveJobInternalTab(searchParams.get('tab'));
    setTab((current) => (current === next ? current : next));
  }, [searchParams]);

  const handleTabChange = React.useCallback((tabId: string) => {
    const next = resolveJobInternalTab(tabId);
    setTab(next);
    setSearchParams({ tab: next }, { replace: true });
    setEventType('');
    setStatus('');
    setSelectedRunId(null);
  }, [setSearchParams]);

  const loadEvents = React.useCallback(() => {
    jobsService
      .getEvents({
        page: 1,
        pageSize: 30,
        direction: 'Internal',
        eventType: eventType || undefined,
        processingStatus: status || undefined,
      })
      .then((r) => setEvents(r.items))
      .catch((e: Error) => toast.error(e.message));
  }, [eventType, status, toast]);

  const loadRuns = React.useCallback(() => {
    jobsService
      .getImportRuns(1, 20)
      .then((r) => setRuns(r.items))
      .catch((e: Error) => toast.error(e.message));
  }, [toast]);

  React.useEffect(() => {
    setLoading(true);
    jobsService
      .getEventTypes('Internal')
      .then(setEventTypes)
      .finally(() => setLoading(false));
  }, []);

  React.useEffect(() => {
    if (tab === 'events') loadEvents();
    else loadRuns();
  }, [tab, loadEvents, loadRuns]);

  React.useEffect(() => {
    if (!selectedRunId) {
      setRunDetail(null);
      return undefined;
    }
    jobsService.getImportRun(selectedRunId).then(setRunDetail).catch(() => undefined);
    if (runDetail?.status === 'Running') {
      const t = setInterval(() => {
        jobsService.getImportRun(selectedRunId).then(setRunDetail).catch(() => undefined);
        loadRuns();
      }, 4000);
      return () => clearInterval(t);
    }
    return undefined;
  }, [selectedRunId, runDetail?.status, loadRuns]);

  return (
    <div data-testid="job-internal-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
      </p>

      <CatalogListPageTabs data-testid="job-internal-tabs">
        <Tabs
          tabs={[...JOB_INTERNAL_TABS]}
          activeTab={tab}
          onTabChange={handleTabChange}
          variant="underline"
        />
      </CatalogListPageTabs>

      {tab === 'events' ? (
        <>
          <JobEventTypeFilter
            eventTypes={eventTypes}
            eventType={eventType}
            onEventTypeChange={setEventType}
            status={status}
            onStatusChange={setStatus}
          />
          <TableCard>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr>
                  <th align="left">EventId</th>
                  <th align="left">Type</th>
                  <th align="left">Status</th>
                  <th align="left">Source</th>
                  <th align="left">Created</th>
                </tr>
              </thead>
              <tbody>
                {events.map((e) => (
                  <tr key={e.eventId}>
                    <td style={{ fontFamily: 'monospace', fontSize: 12 }}>{e.eventId.slice(0, 8)}…</td>
                    <td>{e.eventType}</td>
                    <td>{e.processingStatus}</td>
                    <td>{e.sourceDocumentType ?? '—'}</td>
                    <td>{new Date(e.createdAt).toLocaleString('vi-VN')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </TableCard>
        </>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginTop: 16 }}>
          <TableCard>
            <h4>Danh sách import</h4>
            {loading ? <p>Đang tải…</p> : null}
            <ul style={{ listStyle: 'none', padding: 0 }}>
              {runs.map((r) => (
                <li key={r.id} style={{ marginBottom: 8 }}>
                  <button
                    type="button"
                    onClick={() => setSelectedRunId(r.id)}
                    style={{
                      width: '100%',
                      textAlign: 'left',
                      padding: 8,
                      border: selectedRunId === r.id ? '2px solid #2563eb' : '1px solid #ddd',
                      borderRadius: 6,
                      background: '#fff',
                      cursor: 'pointer',
                    }}
                  >
                    <strong>{r.status}</strong> — {r.trigger}
                    <br />
                    <small>{new Date(r.startedAtUtc).toLocaleString('vi-VN')}</small>
                    <br />
                    <small>
                      Sets: {r.summary.setsSuccess}/{r.summary.setsTotal} ok
                    </small>
                  </button>
                </li>
              ))}
            </ul>
          </TableCard>
          <TableCard>
            <h4>Chi tiết / tiến độ</h4>
            {!runDetail ? (
              <p>Chọn một run</p>
            ) : (
              <>
                <p>
                  <strong>Status:</strong> {runDetail.status}
                </p>
                <p>
                  <strong>Environment:</strong> {runDetail.environmentName}
                </p>
                {runDetail.progress ? (
                  <div>
                    <p>
                      Tiến độ: {runDetail.progress.percent}%
                    </p>
                    <ul>
                      {runDetail.progress.sets.map((s) => (
                        <li key={s.setName}>
                          {s.setName}: {s.done}/{s.total} ({s.percent}%)
                        </li>
                      ))}
                    </ul>
                  </div>
                ) : (
                  <p>Chưa có checkpoint progress</p>
                )}
              </>
            )}
          </TableCard>
        </div>
      )}
    </div>
  );
};

export default JobInternalPage;
