import type { DevRouteBadge } from '../dev/types';

export const PERMISSION_TAB_IDS = [
  'packages',
  'permissions',
  'menu',
  'endpoint',
  'notification',
  'apps',
] as const;

export type PermissionTabId = (typeof PERMISSION_TAB_IDS)[number];

/** §2 phan-quyen-cau-hinh.md — tab mega-page */
export const PERMISSION_TABS: ReadonlyArray<{
  id: PermissionTabId;
  label: string;
  icon: string;
}> = [
  { id: 'packages', label: 'Gói tính năng', icon: 'fas fa-cube' },
  { id: 'permissions', label: 'Quyền truy cập', icon: 'fas fa-key' },
  { id: 'menu', label: 'Menu điều hướng', icon: 'fas fa-bars' },
  { id: 'endpoint', label: 'Endpoint API', icon: 'fas fa-plug' },
  { id: 'notification', label: 'Thông báo', icon: 'fas fa-bell' },
  { id: 'apps', label: 'Ứng dụng', icon: 'fas fa-th-large' },
];

export function resolvePermissionTab(tab: string | null): PermissionTabId {
  if (tab && (PERMISSION_TAB_IDS as readonly string[]).includes(tab)) {
    return tab as PermissionTabId;
  }
  return 'packages';
}

export const JOB_INTERNAL_TAB_IDS = ['import', 'events'] as const;
export type JobInternalTabId = (typeof JOB_INTERNAL_TAB_IDS)[number];

/** §2 theo-doi-job-event.md — JobInternalPage */
export const JOB_INTERNAL_TABS: ReadonlyArray<{ id: JobInternalTabId; label: string }> = [
  { id: 'import', label: 'Lượt import' },
  { id: 'events', label: 'Sự kiện nội bộ' },
];

export function resolveJobInternalTab(tab: string | null): JobInternalTabId {
  if (tab && (JOB_INTERNAL_TAB_IDS as readonly string[]).includes(tab)) {
    return tab as JobInternalTabId;
  }
  return 'import';
}

