import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useNavTitle } from '@linm-soft/common-components';
import { Button, Input, Select, TableCard, Modal, Slideout } from '../../ui';
import { useActiveStatusOptions } from '../../hooks/useAdminFormOptions';
import { useAppToast } from '@linm-soft/common-components';
import {
  companyService,
  type CompanyItem,
  type CreateCompanyRequest,
  type UpdateCompanyRequest,
} from '../../services/company';
import styles from './CompaniesManagementPage.module.css';

interface CompanyFormData {
  code: string;
  name: string;
  shortName: string;
  logoUrl: string;
  address: string;
  phone: string;
  email: string;
  isActive: boolean;
}

const emptyForm: CompanyFormData = {
  code: '',
  name: '',
  shortName: '',
  logoUrl: '',
  address: '',
  phone: '',
  email: '',
  isActive: true,
};

const CompaniesManagementPage: React.FC = () => {
  useNavTitle('Đơn vị / Chi nhánh');
  const toast = useAppToast();
  const { options: statusOptions, getActiveLabel } = useActiveStatusOptions();

  const [items, setItems] = useState<CompanyItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [togglingId, setTogglingId] = useState<string | null>(null);
  const [activeOnly, setActiveOnly] = useState(false);

  const [deleteTarget, setDeleteTarget] = useState<CompanyItem | null>(null);
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [deleting, setDeleting] = useState(false);

  const displayedItems = useMemo(
    () => (activeOnly ? items.filter((i) => i.isActive) : items),
    [items, activeOnly]
  );

  const [detailOpen, setDetailOpen] = useState(false);
  const [detailLoading, setDetailLoading] = useState(false);
  const [selectedCompany, setSelectedCompany] = useState<CompanyItem | null>(null);

  const [formOpen, setFormOpen] = useState(false);
  const [editingCompany, setEditingCompany] = useState<CompanyItem | null>(null);
  const [formData, setFormData] = useState<CompanyFormData>(emptyForm);
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});
  const [saving, setSaving] = useState(false);
  const firstErrorRef = useRef<HTMLDivElement>(null);

  const cancelRef = useRef(false);

  const loadCompanies = useCallback(async () => {
    cancelRef.current = false;
    setLoading(true);

    try {
      const data = await companyService.getAll();
      if (cancelRef.current) return;
      setItems(data);
    } catch (err: unknown) {
      if (!cancelRef.current) {
        toast.fromError(err, 'Không thể tải danh sách công ty');
      }
    } finally {
      if (!cancelRef.current) {
        setLoading(false);
      }
    }
  }, [toast]);

  const openCreate = () => {
    setEditingCompany(null);
    setFormData(emptyForm);
    setFieldErrors({});
    setFormOpen(true);
  };

  const openEdit = (item: CompanyItem) => {
    setEditingCompany(item);
    setFormData({
      code: item.code,
      name: item.name,
      shortName: item.shortName ?? '',
      logoUrl: item.logoUrl ?? '',
      address: item.address ?? '',
      phone: item.phone ?? '',
      email: item.email ?? '',
      isActive: item.isActive,
    });
    setFieldErrors({});
    setFormOpen(true);
  };

  const closeForm = () => {
    if (saving) return;
    setFormOpen(false);
    setEditingCompany(null);
    setFormData(emptyForm);
    setFieldErrors({});
  };

  const openDetail = useCallback(async (id: string) => {
    setDetailOpen(true);
    setDetailLoading(true);
    setSelectedCompany(null);

    try {
      const detail = await companyService.getById(id);
      setSelectedCompany(detail);
    } catch (err: unknown) {
      toast.fromError(err, 'Không thể tải chi tiết công ty');
      setDetailOpen(false);
    } finally {
      setDetailLoading(false);
    }
  }, [toast]);

  const handleFieldChange = (field: keyof CompanyFormData, value: string | boolean) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (fieldErrors[field]) {
      setFieldErrors((prev) => { const next = { ...prev }; delete next[field]; return next; });
    }
  };

  const handleSave = async () => {
    const errors: Record<string, string> = {};
    if (!editingCompany && !formData.code.trim()) errors.code = 'Mã đơn vị không được để trống';
    if (!formData.name.trim()) errors.name = 'Tên đơn vị không được để trống';

    if (Object.keys(errors).length > 0) {
      setFieldErrors(errors);
      setTimeout(() => firstErrorRef.current?.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 0);
      return;
    }

    setSaving(true);
    setFieldErrors({});

    try {
      if (editingCompany) {
        const req: UpdateCompanyRequest = {
          name: formData.name.trim(),
          shortName: formData.shortName.trim() || undefined,
          logoUrl: formData.logoUrl.trim() || undefined,
          address: formData.address.trim() || undefined,
          phone: formData.phone.trim() || undefined,
          email: formData.email.trim() || undefined,
          isActive: formData.isActive,
        };

        await companyService.update(editingCompany.id, req);
        toast.success('Cập nhật đơn vị thành công');
      } else {
        const req: CreateCompanyRequest = {
          code: formData.code.trim(),
          name: formData.name.trim(),
          shortName: formData.shortName.trim() || undefined,
          logoUrl: formData.logoUrl.trim() || undefined,
          address: formData.address.trim() || undefined,
          phone: formData.phone.trim() || undefined,
          email: formData.email.trim() || undefined,
          isActive: formData.isActive,
        };

        await companyService.create(req);
        toast.success('Tạo đơn vị thành công');
      }

      await loadCompanies();
      closeForm();
    } catch (err: unknown) {
      const message = (err as Error)?.message || 'Không thể lưu thông tin đơn vị';
      setFieldErrors({ _general: message });
      toast.fromError(err, message);
    } finally {
      setSaving(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      loadCompanies();
    }, 0);

    return () => {
      clearTimeout(timer);
      cancelRef.current = true;
    };
  }, [loadCompanies]);

  const openDeleteSlideout = (item: CompanyItem) => {
    setDeleteTarget(item);
    setDeleteOpen(true);
  };

  const closeDeleteSlideout = () => {
    if (deleting) return;
    setDeleteOpen(false);
    setDeleteTarget(null);
  };

  const handleDelete = async (type: 'soft' | 'hard') => {
    if (!deleteTarget) return;
    setDeleting(true);
    try {
      if (type === 'soft') {
        if (deleteTarget.isActive) {
          await companyService.toggleStatus(deleteTarget.id);
          toast.success('Đã ngừng hoạt động công ty');
        } else {
          toast.success('Công ty đã ở trạng thái ngừng hoạt động');
        }
      } else {
        await companyService.delete(deleteTarget.id);
        toast.success('Đã xóa công ty khỏi hệ thống');
      }
      await loadCompanies();
      setDeleteOpen(false);
      setDeleteTarget(null);
    } catch (err: unknown) {
      toast.fromError(err, 'Không thể thực hiện thao tác xóa');
    } finally {
      setDeleting(false);
    }
  };

  const handleToggle = async (id: string) => {
    try {
      setTogglingId(id);
      await companyService.toggleStatus(id);
      toast.success('Cập nhật trạng thái công ty thành công');
      await loadCompanies();
    } catch (err: unknown) {
      toast.fromError(err, 'Không thể cập nhật trạng thái công ty');
    } finally {
      setTogglingId(null);
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.header}>
        <h1 className={styles.title}>
          <i className="fas fa-building" />
          Đơn vị / Chi nhánh
        </h1>

        <div className={styles.headerActions}>
          <Button
            variant={activeOnly ? 'primary' : 'secondary'}
            onClick={() => setActiveOnly((v) => !v)}
          >
            <i className="fas fa-filter" />
            {activeOnly ? 'Đang hoạt động' : 'Tất cả'}
          </Button>
          <Button variant="secondary" onClick={loadCompanies}>
            <i className="fas fa-rotate" /> Tải lại
          </Button>
          <Button variant="primary" onClick={openCreate}>
            <i className="fas fa-plus" /> Thêm đơn vị
          </Button>
        </div>
      </div>

      <TableCard>
        {loading && <div className={styles.emptyState}>Đang tải dữ liệu...</div>}

        {!loading && displayedItems.length === 0 && (
          <div className={styles.emptyState}>
            <i className="fas fa-building" />
            <p>{activeOnly ? 'Không có đơn vị đang hoạt động' : 'Chưa có đơn vị nào'}</p>
          </div>
        )}

        {!loading && displayedItems.length > 0 && (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Mã</th>
                  <th>Tên công ty</th>
                  <th>Tên ngắn</th>
                  <th>Email</th>
                  <th>Điện thoại</th>
                  <th>Trạng thái</th>
                  <th className={styles.actionsCell}>Hành động</th>
                </tr>
              </thead>
              <tbody>
                {displayedItems.map((item, idx) => (
                  <tr key={item.id} onClick={() => openDetail(item.id)} className={styles.clickableRow}>
                    <td>{idx + 1}</td>
                    <td>
                      <span className={styles.codeBadge}>{item.code}</span>
                    </td>
                    <td>{item.name}</td>
                    <td>{item.shortName || <span className={styles.na}>—</span>}</td>
                    <td>{item.email || <span className={styles.na}>—</span>}</td>
                    <td>{item.phone || <span className={styles.na}>—</span>}</td>
                    <td>
                      <span
                        className={`${styles.statusBadge} ${item.isActive ? styles.active : styles.inactive}`}
                      >
                        {getActiveLabel(item.isActive)}
                      </span>
                    </td>
                    <td className={styles.actionsCell} onClick={(e) => e.stopPropagation()}>
                      <button
                        className={styles.viewBtn}
                        onClick={() => openDetail(item.id)}
                        title="Xem chi tiết"
                      >
                        <i className="fas fa-eye" />
                      </button>
                      <button
                        className={styles.editBtn}
                        onClick={() => openEdit(item)}
                        title="Chỉnh sửa"
                      >
                        <i className="fas fa-pen" />
                      </button>
                      <button
                        className={styles.toggleBtn}
                        onClick={() => handleToggle(item.id)}
                        disabled={togglingId === item.id}
                        title={item.isActive ? 'Ngừng hoạt động' : 'Kích hoạt lại'}
                      >
                        <i className={item.isActive ? 'fas fa-ban' : 'fas fa-check'} />
                      </button>
                      <button
                        className={styles.deleteBtn}
                        onClick={() => openDeleteSlideout(item)}
                        title="Xóa công ty"
                      >
                        <i className="fas fa-trash" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </TableCard>

      <Slideout
        isOpen={detailOpen}
        onClose={() => setDetailOpen(false)}
        title={
          <span className={styles.slideoutTitle}>
            <i className="fas fa-building" /> Chi tiết công ty
          </span>
        }
        width="560px"
        customFooter={<button className={styles.cancelBtn} onClick={() => setDetailOpen(false)}>Đóng</button>}
      >
        {detailLoading ? (
          <div className={styles.emptyState}>Đang tải dữ liệu...</div>
        ) : selectedCompany ? (
          <div className={styles.detailGrid}>
            <div className={styles.detailItem}><span>Mã công ty</span><strong>{selectedCompany.code}</strong></div>
            <div className={styles.detailItem}><span>Tên công ty</span><strong>{selectedCompany.name}</strong></div>
            <div className={styles.detailItem}><span>Tên ngắn</span><strong>{selectedCompany.shortName || '—'}</strong></div>
            <div className={styles.detailItem}><span>Email</span><strong>{selectedCompany.email || '—'}</strong></div>
            <div className={styles.detailItem}><span>Điện thoại</span><strong>{selectedCompany.phone || '—'}</strong></div>
            <div className={styles.detailItem}><span>Địa chỉ</span><strong>{selectedCompany.address || '—'}</strong></div>
            <div className={styles.detailItem}><span>Logo URL</span><strong>{selectedCompany.logoUrl || '—'}</strong></div>
            <div className={styles.detailItem}><span>Trạng thái</span><strong>{getActiveLabel(selectedCompany.isActive)}</strong></div>
            <div className={styles.detailItem}><span>Ngày tạo</span><strong>{new Date(selectedCompany.createdAt).toLocaleString('vi-VN')}</strong></div>
            <div className={styles.detailItem}><span>Cập nhật</span><strong>{selectedCompany.updatedAt ? new Date(selectedCompany.updatedAt).toLocaleString('vi-VN') : '—'}</strong></div>
          </div>
        ) : null}
      </Slideout>

      <Modal
        isOpen={formOpen}
        onClose={closeForm}
        title={editingCompany ? 'Chỉnh sửa đơn vị' : 'Thêm đơn vị mới'}
        size="lg"
        closeOnOverlayClick={!saving}
      >
        <div className={styles.formWrapper} ref={firstErrorRef}>
          <div className={styles.formRow}>
            <Input
              label="Mã đơn vị"
              value={formData.code}
              onChange={(e) => handleFieldChange('code', e.target.value.toUpperCase())}
              placeholder="VD: LINM-HN-001"
              disabled={!!editingCompany}
              error={fieldErrors.code}
              required
              fullWidth
            />
            <Input
              label="Tên đơn vị"
              value={formData.name}
              onChange={(e) => handleFieldChange('name', e.target.value)}
              placeholder="Nhập tên đơn vị"
              error={fieldErrors.name}
              required
              fullWidth
            />
          </div>

          <div className={styles.formRow}>
            <Input
              label="Tên ngắn"
              value={formData.shortName}
              onChange={(e) => handleFieldChange('shortName', e.target.value)}
              placeholder="VD: Linm HN"
              fullWidth
            />
            <Input
              label="Logo URL"
              value={formData.logoUrl}
              onChange={(e) => handleFieldChange('logoUrl', e.target.value)}
              placeholder="https://..."
              fullWidth
            />
          </div>

          <div className={styles.formRow}>
            <Input
              label="Email"
              type="email"
              value={formData.email}
              onChange={(e) => handleFieldChange('email', e.target.value)}
              placeholder="company@domain.com"
              fullWidth
            />
            <Input
              label="Điện thoại"
              value={formData.phone}
              onChange={(e) => handleFieldChange('phone', e.target.value)}
              placeholder="0xxxxxxxxx"
              fullWidth
            />
          </div>

          <Input
            label="Địa chỉ"
            value={formData.address}
            onChange={(e) => handleFieldChange('address', e.target.value)}
            placeholder="Nhập địa chỉ"
            fullWidth
          />

          <Select
            label="Trạng thái"
            value={formData.isActive ? 'active' : 'inactive'}
            onChange={(e) => handleFieldChange('isActive', e.target.value === 'active')}
            options={statusOptions.length >= 2 ? statusOptions : [
              { value: 'active', label: statusOptions[0]?.label ?? 'Hoạt động' },
              { value: 'inactive', label: statusOptions[1]?.label ?? 'Ngừng hoạt động' },
            ]}
            fullWidth
          />

          {fieldErrors._general && <div className={styles.formError}>{fieldErrors._general}</div>}
        </div>
        <div className={styles.modalFooter}>
          <button className={styles.cancelBtn} onClick={closeForm} disabled={saving}>Hủy</button>
          <button className={styles.saveBtn} onClick={handleSave} disabled={saving}>
            {saving ? <><i className="fas fa-spinner fa-spin" /> Đang lưu...</> : <><i className="fas fa-check" /> Lưu</>}
          </button>
        </div>
      </Modal>

      <Slideout
        isOpen={deleteOpen}
        onClose={closeDeleteSlideout}
        title={
          <span className={styles.slideoutTitle}>
            <i className="fas fa-trash" /> Xóa công ty
          </span>
        }
        width="480px"
        customFooter={
          <button className={styles.cancelBtn} onClick={closeDeleteSlideout} disabled={deleting}>
            Hủy
          </button>
        }
      >
        {deleteTarget && (
          <div className={styles.formWrapper}>
            <p className={styles.deleteInfo}>
              Bạn muốn xử lý công ty <strong>{deleteTarget.name}</strong> ({deleteTarget.code}) như thế nào?
            </p>

            <div className={styles.deleteOptions}>
              <button
                className={styles.softDeleteBtn}
                onClick={() => handleDelete('soft')}
                disabled={deleting || !deleteTarget.isActive}
              >
                <i className="fas fa-ban" />
                <span>Ngừng hoạt động</span>
                <small>Giữ dữ liệu, đánh dấu không hoạt động</small>
              </button>

              <button
                className={styles.hardDeleteBtn}
                onClick={() => handleDelete('hard')}
                disabled={deleting}
              >
                <i className="fas fa-trash-alt" />
                <span>Xóa hoàn toàn</span>
                <small>Xóa vĩnh viễn khỏi cơ sở dữ liệu</small>
              </button>
            </div>

            {deleting && (
              <div className={styles.deletingIndicator}>
                <i className="fas fa-spinner fa-spin" /> Đang xử lý...
              </div>
            )}
          </div>
        )}
      </Slideout>
    </div>
  );
};

export default CompaniesManagementPage;
